function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const TESTPHP="if ( ! defined('ABSPATH') ) { return; }\nadd_action('wp_loaded', function(){\n  if ( ! isset($_GET['ps_m8_test']) ) { return; }\n  if ( ($_GET['token']??'') !== 'cmplz_6680aa2a42151d54fa8d64ec' ) { return; }\n  $out = array();\n  global $wpdb;\n\n  $out['0_ver'] = defined('PETSHOP_CORE_VERSION') ? PETSHOP_CORE_VERSION : '?';\n  $out['0_petprofile'] = class_exists('Petshop_Pet_Profile');\n  $out['0_petproducts'] = class_exists('Petshop_Pet_Products');\n  $out['0_pets_table'] = (bool)$wpdb->get_var(\"SHOW TABLES LIKE '{$wpdb->prefix}ps_pets'\");\n  $out['0_petprod_table'] = (bool)$wpdb->get_var(\"SHOW TABLES LIKE '{$wpdb->prefix}ps_pet_products'\");\n\n  // Ar nauji ps_pets laukai prid\u0117ti?\n  $cols = $wpdb->get_col(\"SHOW COLUMNS FROM {$wpdb->prefix}ps_pets\");\n  $new_fields = array('species_detail','is_sterilised','current_food_free_text','primary_product_id','photo_file_id','status','deleted_at');\n  $missing = array_diff($new_fields, $cols);\n  $out['1_new_columns'] = empty($missing) ? 'ALL PRESENT' : ('MISSING: '.implode(',',$missing));\n\n  // Test user\n  $uid = wp_create_user('ps_test_m8', wp_generate_password(), 'terra@gyvunai.lt');\n  if(is_wp_error($uid)){ $user = get_user_by('email','terra@gyvunai.lt'); $uid = $user->ID; }\n  wp_set_current_user($uid);\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id=%d\", $uid));\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pet_products WHERE user_id=%d\", $uid));\n\n  // 2. CREATE su naujais laukais (pauk\u0161tis su species_detail)\n  $req = new WP_REST_Request('POST', '/petshop/v1/pet-profile');\n  $req->set_param('species', 'bird');\n  $req->set_param('species_detail', 'Banguotoji pap\u016bg\u0117l\u0117');\n  $req->set_param('pet_name', 'Coco');\n  $req->set_param('life_stage', 'adult');\n  $resp = rest_do_request($req);\n  $data = $resp->get_data();\n  $pet_id = $data['pet_id'] ?? 0;\n  $out['2_create_bird'] = array('status'=>$resp->get_status(), 'pet_id'=>$pet_id);\n  $saved = $wpdb->get_row($wpdb->prepare(\"SELECT species,species_detail,pet_name FROM {$wpdb->prefix}ps_pets WHERE id=%d\", $pet_id));\n  $out['2_saved'] = array('species'=>$saved->species, 'detail'=>$saved->species_detail, 'name'=>$saved->pet_name);\n\n  // 3. Naujas primary_need enum (skin_allergy)\n  $req2 = new WP_REST_Request('POST', '/petshop/v1/pet-profile');\n  $req2->set_param('species', 'dog');\n  $req2->set_param('pet_name', 'Reksas');\n  $req2->set_param('primary_need', 'skin_allergy');\n  $req2->set_param('is_sterilised', 'yes');\n  $resp2 = rest_do_request($req2);\n  $dog_id = $resp2->get_data()['pet_id'] ?? 0;\n  $saved2 = $wpdb->get_row($wpdb->prepare(\"SELECT primary_need FROM {$wpdb->prefix}ps_pets WHERE id=%d\", $dog_id));\n  $out['3_skin_allergy'] = ($saved2->primary_need === 'skin_allergy') ? 'OK' : ('BLOGAI: '.$saved2->primary_need);\n\n  // 4. PATCH endpoint\n  $reqP = new WP_REST_Request('PATCH', '/petshop/v1/pet-profile/' . $dog_id);\n  $reqP->set_param('dog_size', 'large');\n  $respP = rest_do_request($reqP);\n  $out['4_patch'] = array('status'=>$respP->get_status(), 'changed'=>$respP->get_data()['changed_fields']??null);\n\n  // 5. Brands autocomplete\n  $reqB = new WP_REST_Request('GET', '/petshop/v1/brands');\n  $reqB->set_param('q', 'Jose');\n  $respB = rest_do_request($reqB);\n  $brands = $respB->get_data()['brands'] ?? array();\n  $out['5_brands'] = array('count'=>count($brands), 'sample'=>array_slice(array_map(function($b){return $b['name'];}, $brands),0,3));\n\n  // 6. Pet-product-link (priskyrimas)\n  $prods = wc_get_products(array('limit'=>1, 'status'=>'publish'));\n  if(!empty($prods)){\n    $prod_id = $prods[0]->get_id();\n    $reqL = new WP_REST_Request('POST', '/petshop/v1/pet-product-link');\n    $reqL->set_param('pet_id', $dog_id);\n    $reqL->set_param('product_id', $prod_id);\n    $reqL->set_param('relationship_type', 'primary_food');\n    $respL = rest_do_request($reqL);\n    $out['6_link'] = array('status'=>$respL->get_status(), 'link_id'=>$respL->get_data()['link_id']??null);\n\n    // GET lentyn\u0117l\u0117\n    $reqLG = new WP_REST_Request('GET', '/petshop/v1/pet-product-link');\n    $reqLG->set_param('pet_id', $dog_id);\n    $respLG = rest_do_request($reqLG);\n    $out['6_shelf'] = count($respLG->get_data()['products'] ?? array());\n  }\n\n  // 7. Soft DELETE\n  $reqD = new WP_REST_Request('DELETE', '/petshop/v1/pet-profile/' . $pet_id);\n  $respD = rest_do_request($reqD);\n  $out['7_soft_delete'] = array('status'=>$respD->get_status(), 'deleted'=>$respD->get_data()['deleted']??null);\n  // Patikrinam kad status=deleted, ne fizi\u0161kai i\u0161trintas\n  $still = $wpdb->get_row($wpdb->prepare(\"SELECT status,deleted_at FROM {$wpdb->prefix}ps_pets WHERE id=%d\", $pet_id));\n  $out['7_soft_verify'] = ($still && $still->status === 'deleted' && $still->deleted_at) ? 'OK (soft)' : 'BLOGAI';\n  // LIST neturi rodyti deleted\n  $reqLST = new WP_REST_Request('GET', '/petshop/v1/pet-profile');\n  $respLST = rest_do_request($reqLST);\n  $out['7_list_excludes_deleted'] = count($respLST->get_data()['pets'] ?? array());  // turi b\u016bti 1 (tik Reksas)\n\n  // cleanup\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pets WHERE user_id=%d\", $uid));\n  $wpdb->query($wpdb->prepare(\"DELETE FROM {$wpdb->prefix}ps_pet_products WHERE user_id=%d\", $uid));\n  $wpdb->query(\"DELETE FROM {$wpdb->prefix}ps_event_log WHERE event_name LIKE 'pet_%'\");\n  require_once ABSPATH.'wp-admin/includes/user.php';\n  $u=get_user_by('login','ps_test_m8'); if($u) wp_delete_user($u->ID);\n  $out['9_cleanup'] = 'done';\n\n  header('Content-Type: application/json; charset=utf-8');\n  echo wp_json_encode($out, JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_PRETTY_PRINT);\n  exit;\n}, 6);";
const F={"main": "", "petprofile": "", "petproducts": "", "registry": "", "schema_assigned": "", "schema_feedback": ""};
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -A "Mozilla/5.0" --max-time 90 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -A "Mozilla/5.0" --max-time 60 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'')+'\nHTTP:TIMEOUT';}return{code:(r.match(/HTTP:(\S+)$/)||[])[1]||'?',body:r.replace(/\nHTTP:\S+$/,'')};}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
